import argparse
from kafka import KafkaAdminClient, NewPartitions, NewTopic

def create_topic(admin_client, topic_name, num_partitions, num_replicas):
    topic = NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=num_replicas)
    admin_client.create_topics(new_topics=[topic])

def manage_partitions(admin_client, topic_name, num_partitions):
    partitions = NewPartitions(total_count=num_partitions)
    admin_client.create_partitions({topic_name: partitions})

def alter_configs(admin_client, topic_name, configs):
    admin_client.alter_configs(resource_type="topic", resources={topic_name: configs})

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--bootstrap_servers", required=True)
    parser.add_argument("--topic_name", required=True)
    parser.add_argument("--num_partitions", type=int, default=1)
    parser.add_argument("--num_replicas", type=int, default=1)
    parser.add_argument("--new_partitions", type=int, default=None)
    parser.add_argument("--configs", type=str, default=None)
    args = parser.parse_args()

    admin_client = KafkaAdminClient(bootstrap_servers=args.bootstrap_servers)

    create_topic(admin_client, args.topic_name, args.num_partitions, args.num_replicas)

    if args.new_partitions:
        manage_partitions(admin_client, args.topic_name, args.new_partitions)

    if args.configs:
        configs = dict(c.split("=") for c in args.configs.split(","))
        alter_configs(admin_client, args.topic_name, configs)


if __name__ == "__main__":
    main()